type CampaignMapProps = {
  highestUnlockedStage: number
  currentStage: number
  completedStages: number[]
  onSelectStage: (stage: number) => void
}

const STAGES = [1, 2, 3, 4, 5] as const

function getStageState(stage: number, highestUnlockedStage: number, completedStages: number[]): 'locked' | 'unlocked' | 'completed' {
  if (completedStages.includes(stage)) {
    return 'completed'
  }

  if (stage > highestUnlockedStage) {
    return 'locked'
  }

  return 'unlocked'
}

export function CampaignMap({ highestUnlockedStage, currentStage, completedStages, onSelectStage }: CampaignMapProps) {
  return (
    <section className="mb-6 rounded-xl border border-slate-700 bg-slate-900/70 p-6">
      <div className="mb-4 flex items-center justify-between">
        <h2 className="text-xl font-semibold text-slate-100">Mapa da campanha</h2>
        <p className="text-sm font-semibold text-indigo-300">Fase atual: {currentStage}</p>
      </div>

      <div className="grid grid-cols-1 gap-4 md:grid-cols-5">
        {STAGES.map((stage, index) => {
          const stageState = getStageState(stage, highestUnlockedStage, completedStages)
          const isLocked = stageState === 'locked'
          const isCompleted = stageState === 'completed'
          const isCurrent = stage === currentStage

          return (
            <div key={stage} className="relative">
              {index < STAGES.length - 1 ? (
                <span className="pointer-events-none absolute right-[-18px] top-1/2 hidden h-[2px] w-9 -translate-y-1/2 bg-slate-600 md:block" />
              ) : null}

              <button
                className={[
                  'flex h-28 w-full flex-col items-center justify-center rounded-lg border px-4 py-3 text-center transition',
                  isCompleted ? 'border-emerald-400 bg-emerald-500/10 text-emerald-100' : '',
                  stageState === 'unlocked' ? 'border-indigo-400 bg-indigo-500/10 text-indigo-100 hover:bg-indigo-500/20' : '',
                  isLocked ? 'cursor-not-allowed border-slate-700 bg-slate-800 text-slate-400' : '',
                  isCurrent ? 'ring-2 ring-indigo-500' : ''
                ].join(' ')}
                type="button"
                disabled={isLocked}
                onClick={() => onSelectStage(stage)}
              >
                <span className="text-sm font-semibold">Fase {stage}</span>
                <span className="mt-2 text-sm font-normal">
                  {isCompleted ? 'Concluida' : stageState === 'unlocked' ? 'Desbloqueada' : 'Bloqueada'}
                </span>
                {isLocked ? (
                  <span className="mt-2 text-xs font-semibold text-slate-300">Derrote o chefe da fase anterior para desbloquear</span>
                ) : null}
              </button>
            </div>
          )
        })}
      </div>
    </section>
  )
}

import { useCallback, useEffect, useMemo, useRef, useState } from 'react'
import { CampaignMap } from './components/CampaignMap'
import { GameOverlay } from './components/GameOverlay'
import { HUD } from './components/HUD'
import { SettingsPanel } from './components/SettingsPanel'
import { ShopScreen } from './components/ShopScreen'
import {
  continueToNextStage,
  pauseGame,
  restartRound,
  resumeGame,
  startGame,
  startRound,
  stopGame
} from './game/engine'
import { useVisibilityPause } from './hooks/useVisibilityPause'
import { setTelemetryConsent } from './lib/telemetry'
import { getPersistedProgressProfile, resolveInterruptedRunSnapshot } from './services/shopPersistenceService'
import { loadSettings, saveSettings } from './services/settingsService'
import { EMPTY_UPGRADE_LEVELS, listActiveUpgrades, type UpgradeLevels } from './services/shopService'
import { applyRunModifierSelection, type RunModifierId } from './game/systems/runModifierSystem'
import { isBossStage } from './game/config/gameplay'
import { gameStore } from './state/gameStore'
import { settingsStore, type GameSettings } from './state/settingsStore'
import type { GameSessionState } from './game/types'

export default function App() {
  const canvasRef = useRef<HTMLCanvasElement | null>(null)
  const [gameState, setGameState] = useState<GameSessionState>(gameStore.getState())
  const [settings, setSettings] = useState<GameSettings>(settingsStore.getState())
  const [isSettingsOpen, setIsSettingsOpen] = useState(false)
  const [upgradeLevels, setUpgradeLevels] = useState<UpgradeLevels>({ ...EMPTY_UPGRADE_LEVELS })
  const [showCompletionOverlay, setShowCompletionOverlay] = useState(false)
  const [showInterruptedRunPrompt, setShowInterruptedRunPrompt] = useState(false)

  const completedStages = useMemo(() => {
    const completedUntil = Math.max(0, Math.min(5, gameState.progressionProfile.lastCompletedStage ?? 0))
    return Array.from({ length: completedUntil }, (_, index) => index + 1)
  }, [gameState.progressionProfile.lastCompletedStage])

  if (typeof window !== 'undefined') {
    ;(window as Window & { __GAME_STORE__?: typeof gameStore }).__GAME_STORE__ = gameStore
  }

  const handlePrimaryOverlayAction = useCallback(() => {
    if (gameState.status === 'idle') {
      startRound()
      return
    }

    if (gameState.status === 'paused') {
      resumeGame()
      return
    }

    if (gameState.status === 'game-over') {
      setUpgradeLevels({ ...EMPTY_UPGRADE_LEVELS })
      restartRound()
    }
  }, [gameState.status])

  useVisibilityPause({
    onPause: pauseGame,
    onResume: () => {
      if (gameStore.getState().status === 'paused') {
        resumeGame()
      }
    }
  })

  useEffect(() => {
    if (gameState.status === 'shop') {
      setShowCompletionOverlay(true)
    }
  }, [gameState.status])

  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return

    startGame(canvas)

    const unsubscribe = gameStore.subscribe((state) => {
      setGameState(state)
    })
    const unsubscribeSettings = settingsStore.subscribe((nextSettings) => {
      setSettings(nextSettings)
    })

    void getPersistedProgressProfile().then((profile) => {
      const levels = { ...EMPTY_UPGRADE_LEVELS }
      const fallbackStage = gameStore.getState().stage
      const interruptedRun = resolveInterruptedRunSnapshot(profile.interruptedRun, fallbackStage)

      setUpgradeLevels(levels)
      gameStore.setState({
        upgradeLevels: levels,
        activeUpgrades: listActiveUpgrades(levels),
        progressionProfile: {
          highestUnlockedStage: profile.highestUnlockedStage,
          totalRuns: profile.totalRuns,
          lastAttemptedStage: profile.lastAttemptedStage,
          lastCompletedStage: profile.lastCompletedStage,
          interruptedRun
        }
      })

      if (interruptedRun) {
        setShowInterruptedRunPrompt(true)
      }
    })

    void loadSettings().then((savedSettings) => {
      if (!savedSettings) {
        return
      }

      settingsStore.setState(savedSettings)
      setTelemetryConsent(savedSettings.telemetryConsent)
    })

    return () => {
      unsubscribe()
      unsubscribeSettings()
      stopGame()
    }
  }, [])

  const handleSettingsChange = (partial: Partial<GameSettings>) => {
    settingsStore.setState(partial)
    const nextSettings = settingsStore.getState()
    setTelemetryConsent(nextSettings.telemetryConsent)
    void saveSettings(nextSettings)
  }

  const handleResumeInterruptedRun = () => {
    setShowInterruptedRunPrompt(false)

    if (gameStore.getState().status === 'paused') {
      resumeGame()
      return
    }

    startRound()
  }

  const handleRestartInterruptedRun = () => {
    setShowInterruptedRunPrompt(false)
    restartRound()
  }

  const handleSelectStage = (stage: number) => {
    if (stage > gameState.progressionProfile.highestUnlockedStage) {
      return
    }

    gameStore.setState({
      stage,
      progressionProfile: {
        ...gameState.progressionProfile,
        lastAttemptedStage: stage,
        interruptedRun: null
      }
    })
  }

  return (
    <div
      className={`min-h-screen bg-gradient-to-b from-slate-900 to-slate-800 text-white flex items-center justify-center ${
        settings.highContrast ? 'high-contrast' : ''
      }`}
    >
      <div className="w-full max-w-5xl p-4">
        <CampaignMap
          highestUnlockedStage={gameState.progressionProfile.highestUnlockedStage}
          currentStage={gameState.stage}
          completedStages={completedStages}
          onSelectStage={handleSelectStage}
        />

        <div className="bg-slate-900/60 rounded-lg p-4 shadow-lg">
          <div className="mb-3 flex items-center justify-between">
            <h1 className="text-2xl font-semibold">Space Invaders - Modern UI</h1>
            <button
              className="rounded-md bg-slate-700 px-3 py-1.5 text-sm font-medium hover:bg-slate-600"
              onClick={() => setIsSettingsOpen(true)}
              type="button"
            >
              Configuracoes
            </button>
          </div>
          <div className="relative overflow-hidden rounded bg-black">
            <HUD
              score={gameState.score}
              lives={gameState.lives}
              stage={gameState.stage}
              highScore={gameState.highScore}
              bossHealth={gameState.bossEncounter.active ? gameState.bossEncounter.health : undefined}
              bossMaxHealth={gameState.bossEncounter.active ? gameState.bossEncounter.maxHealth : undefined}
              captionsEnabled={settings.captionsEnabled}
              highestUnlockedStage={gameState.progressionProfile.highestUnlockedStage}
              completedCount={completedStages.length}
              statusLabel={
                gameState.status === 'running'
                  ? isBossStage(gameState.stage)
                    ? 'boss na fase'
                    : undefined
                  : gameState.status
              }
            />
            <canvas ref={canvasRef} width={800} height={480} className="w-full h-auto rounded bg-black" />
            <GameOverlay
              status={gameState.status}
              activePowerUps={gameState.activePowerUps}
              bossHealth={gameState.bossEncounter.active ? gameState.bossEncounter.health : undefined}
              bossMaxHealth={gameState.bossEncounter.active ? gameState.bossEncounter.maxHealth : undefined}
              nowMs={Date.now()}
              showCompletion={showCompletionOverlay && gameState.status === 'shop'}
              showInterruptedRunPrompt={showInterruptedRunPrompt}
              onPrimaryAction={handlePrimaryOverlayAction}
              onContinueStage={() => {
                setShowCompletionOverlay(false)
                continueToNextStage(gameStore.getState().upgradeLevels)
              }}
              onResumeInterruptedRun={handleResumeInterruptedRun}
              onRestartInterruptedRun={handleRestartInterruptedRun}
            />
            {gameState.status === 'shop' ? (
              <ShopScreen
                score={gameState.score}
                lives={gameState.lives}
                upgradeLevels={upgradeLevels}
                runModifierOffer={gameState.runModifierOffer}
                onSelectRunModifier={(modifierId) => {
                  const nextUpgradeLevels = applyRunModifierSelection(upgradeLevels, modifierId as RunModifierId)
                  setUpgradeLevels(nextUpgradeLevels)
                  gameStore.setState({
                    upgradeLevels: nextUpgradeLevels,
                    activeUpgrades: listActiveUpgrades(nextUpgradeLevels),
                    runModifierOffer: gameState.runModifierOffer
                      ? {
                          ...gameState.runModifierOffer,
                          selectedModifierId: modifierId
                        }
                      : null
                  })
                }}
                onPurchase={(nextScore, nextUpgradeLevels) => {
                  setUpgradeLevels(nextUpgradeLevels)
                  gameStore.setState({
                    score: nextScore,
                    upgradeLevels: nextUpgradeLevels,
                    activeUpgrades: listActiveUpgrades(nextUpgradeLevels)
                  })
                }}
                onPurchaseExtraLife={(nextScore, nextLives) => {
                  gameStore.setState({
                    score: nextScore,
                    lives: nextLives
                  })
                }}
                onContinue={() => {
                  setShowCompletionOverlay(false)
                  continueToNextStage(gameStore.getState().upgradeLevels)
                }}
              />
            ) : null}
            <SettingsPanel
              isOpen={isSettingsOpen}
              onChange={handleSettingsChange}
              onClose={() => setIsSettingsOpen(false)}
              settings={settings}
            />
          </div>
        </div>
      </div>
    </div>
  )
}

import { getRecord, putRecord } from '../lib/indexedDb'
import {
  EMPTY_UPGRADE_LEVELS,
  type ShopItemId,
  type UpgradeLevels
} from './shopService'

type UpgradesRecord = {
  id: 'owned-upgrades'
  upgrades?: ShopItemId[]
  upgradeLevels?: UpgradeLevels
  updatedAt: string
}

export type InterruptedRunSnapshot = {
  stage: number
  atStatus: 'running' | 'paused'
  savedAt: string
}

export type ProgressProfile = {
  id: 'player-progress'
  highestUnlockedStage: number
  totalRuns: number
  lastAttemptedStage: number | null
  lastCompletedStage: number | null
  interruptedRun: InterruptedRunSnapshot | null
  updatedAt: string
}

const STORE_ID = 'owned-upgrades'
const PROGRESS_PROFILE_ID = 'player-progress'

function createDefaultProgressProfile(): ProgressProfile {
  return {
    id: PROGRESS_PROFILE_ID,
    highestUnlockedStage: 1,
    totalRuns: 0,
    lastAttemptedStage: null,
    lastCompletedStage: null,
    interruptedRun: null,
    updatedAt: new Date().toISOString()
  }
}

export function isValidInterruptedRunSnapshot(value: unknown): value is InterruptedRunSnapshot {
  if (!value || typeof value !== 'object') {
    return false
  }

  const candidate = value as Record<string, unknown>
  const validStatus = candidate.atStatus === 'running' || candidate.atStatus === 'paused'

  return (
    typeof candidate.stage === 'number' &&
    Number.isFinite(candidate.stage) &&
    candidate.stage >= 1 &&
    validStatus &&
    typeof candidate.savedAt === 'string' &&
    candidate.savedAt.length > 0
  )
}

export async function getPersistedUpgradeLevels(): Promise<UpgradeLevels> {
  const record = await getRecord<UpgradesRecord>('upgrades', STORE_ID)
  if (!record) {
    return { ...EMPTY_UPGRADE_LEVELS }
  }

  if (record.upgradeLevels) {
    return {
      ...EMPTY_UPGRADE_LEVELS,
      ...record.upgradeLevels
    }
  }

  const migrated = { ...EMPTY_UPGRADE_LEVELS }
  for (const upgrade of record.upgrades ?? []) {
    migrated[upgrade] = Math.max(1, migrated[upgrade])
  }

  return migrated
}

export async function savePersistedUpgradeLevels(upgradeLevels: UpgradeLevels): Promise<void> {
  await putRecord<UpgradesRecord>('upgrades', {
    id: STORE_ID,
    upgradeLevels,
    updatedAt: new Date().toISOString()
  })
}

export async function getPersistedUpgrades(): Promise<ShopItemId[]> {
  const levels = await getPersistedUpgradeLevels()
  return (Object.keys(levels) as ShopItemId[]).filter((upgrade) => levels[upgrade] > 0)
}

export async function savePersistedUpgrades(upgrades: ShopItemId[]): Promise<void> {
  const levels = { ...EMPTY_UPGRADE_LEVELS }
  for (const upgrade of upgrades) {
    levels[upgrade] = 1
  }

  await savePersistedUpgradeLevels(levels)
}

export async function getPersistedProgressProfile(): Promise<ProgressProfile> {
  const record = await getRecord<Partial<ProgressProfile>>('upgrades', PROGRESS_PROFILE_ID)
  if (!record) {
    return createDefaultProgressProfile()
  }

  const defaults = createDefaultProgressProfile()
  const normalizedAttempted = typeof record.lastAttemptedStage === 'number' ? Math.max(1, record.lastAttemptedStage) : null
  const normalizedCompleted = typeof record.lastCompletedStage === 'number' ? Math.max(1, record.lastCompletedStage) : null

  return {
    id: PROGRESS_PROFILE_ID,
    highestUnlockedStage: Math.max(1, record.highestUnlockedStage ?? defaults.highestUnlockedStage),
    totalRuns: Math.max(0, record.totalRuns ?? defaults.totalRuns),
    lastAttemptedStage: normalizedAttempted,
    lastCompletedStage: normalizedCompleted,
    interruptedRun: isValidInterruptedRunSnapshot(record.interruptedRun) ? record.interruptedRun : null,
    updatedAt: typeof record.updatedAt === 'string' ? record.updatedAt : defaults.updatedAt
  }
}

export async function savePersistedProgressProfile(profile: Omit<ProgressProfile, 'id' | 'updatedAt'>): Promise<void> {
  await putRecord<ProgressProfile>('upgrades', {
    id: PROGRESS_PROFILE_ID,
    highestUnlockedStage: Math.max(1, profile.highestUnlockedStage),
    totalRuns: Math.max(0, profile.totalRuns),
    lastAttemptedStage: typeof profile.lastAttemptedStage === 'number' ? Math.max(1, profile.lastAttemptedStage) : null,
    lastCompletedStage: typeof profile.lastCompletedStage === 'number' ? Math.max(1, profile.lastCompletedStage) : null,
    interruptedRun: isValidInterruptedRunSnapshot(profile.interruptedRun) ? profile.interruptedRun : null,
    updatedAt: new Date().toISOString()
  })
}


export function resolveInterruptedRunSnapshot(
  value: unknown,
  fallbackStage: number
): InterruptedRunSnapshot | null {
  if (!isValidInterruptedRunSnapshot(value)) {
    return null
  }

  return {
    stage: value.stage >= 1 ? value.stage : Math.max(1, fallbackStage),
    atStatus: value.atStatus,
    savedAt: value.savedAt
  }
}

import { fireEvent, render, screen } from '@testing-library/react'
import { beforeEach, describe, expect, it, vi } from 'vitest'
import { evaluateStageProgression } from '../../src/game/systems/progressionSystem'
import { spawnBossForWave } from '../../src/game/systems/bossSystem'
import { resolveBossProjectileCollisions } from '../../src/game/systems/collisionSystem'
import { createBossForStage } from '../../src/game/entities/boss'
import { CampaignMap } from '../../src/components/CampaignMap'
import { GameOverlay } from '../../src/components/GameOverlay'
import type { WaveState } from '../../src/game/systems/waveSystem'

const { getRecordMock, putRecordMock } = vi.hoisted(() => ({
  getRecordMock: vi.fn(),
  putRecordMock: vi.fn()
}))

vi.mock('../../src/lib/indexedDb', () => ({
  getRecord: getRecordMock,
  putRecord: putRecordMock
}))

import {
  getPersistedProgressProfile,
  resolveInterruptedRunSnapshot,
  savePersistedProgressProfile
} from '../../src/services/shopPersistenceService'

describe('US1 boss stage flow', () => {
  beforeEach(() => {
    getRecordMock.mockReset()
    putRecordMock.mockReset()
  })

  it('entra em boss fight ao limpar inimigos e avanca para loja apos derrotar chefe', () => {
    const beforeBoss = evaluateStageProgression(10, 0, false, false)
    expect(beforeBoss.enterBossFight).toBe(true)
    expect(beforeBoss.enterShop).toBe(false)

    const waveWithEnemiesCleared: WaveState = {
      stage: 10,
      enemies: [],
      boss: null,
      direction: 1
    }

    const withBoss = spawnBossForWave(waveWithEnemiesCleared)
    expect(withBoss.boss).not.toBeNull()

    const boss = {
      ...createBossForStage(10),
      x: 100,
      y: 100,
      width: 50,
      height: 40,
      health: 1,
      maxHealth: 1
    }

    const hit = resolveBossProjectileCollisions(boss, [
      {
        id: 'player-shot',
        origin: 'player',
        kind: 'default',
        x: 110,
        y: 110,
        width: 4,
        height: 12,
        speedY: -400,
        speedX: 0
      }
    ])

    expect(hit.bossDefeated).toBe(true)

    const afterBoss = evaluateStageProgression(10, 0, true, hit.bossDefeated)
    expect(afterBoss.enterShop).toBe(true)
    expect(afterBoss.nextStage).toBe(11)
  })

  it('migra perfil legado com defaults seguros para novos campos de campanha', async () => {
    getRecordMock.mockResolvedValue({
      id: 'player-progress',
      highestUnlockedStage: 3,
      totalRuns: 8,
      updatedAt: '2026-01-01T10:00:00.000Z'
    })

    const profile = await getPersistedProgressProfile()

    expect(profile.highestUnlockedStage).toBe(3)
    expect(profile.totalRuns).toBe(8)
    expect(profile.lastAttemptedStage).toBeNull()
    expect(profile.lastCompletedStage).toBeNull()
    expect(profile.interruptedRun).toBeNull()
  })

  it('persiste sequencia de checkpoints (inicio, pausa e conclusao) sem dependencia de rede', async () => {
    const fetchSpy = vi.fn()
    vi.stubGlobal('fetch', fetchSpy)

    await savePersistedProgressProfile({
      highestUnlockedStage: 3,
      totalRuns: 9,
      lastAttemptedStage: 3,
      lastCompletedStage: 2,
      interruptedRun: null
    })

    await savePersistedProgressProfile({
      highestUnlockedStage: 3,
      totalRuns: 9,
      lastAttemptedStage: 3,
      lastCompletedStage: 2,
      interruptedRun: {
        stage: 3,
        atStatus: 'paused',
        savedAt: '2026-03-24T18:00:00.000Z'
      }
    })

    await savePersistedProgressProfile({
      highestUnlockedStage: 4,
      totalRuns: 9,
      lastAttemptedStage: 3,
      lastCompletedStage: 3,
      interruptedRun: null
    })

    expect(putRecordMock).toHaveBeenCalledTimes(3)

    const lastCall = putRecordMock.mock.calls[2]?.[1]
    expect(lastCall.highestUnlockedStage).toBe(4)
    expect(lastCall.lastAttemptedStage).toBe(3)
    expect(lastCall.lastCompletedStage).toBe(3)
    expect(lastCall.interruptedRun).toBeNull()
    expect(fetchSpy).not.toHaveBeenCalled()

    vi.unstubAllGlobals()
  })

  it('retorna fallback seguro quando interrupted payload e invalido', () => {
    const invalid = resolveInterruptedRunSnapshot({ stage: 0, atStatus: 'invalid', savedAt: '' }, 2)
    expect(invalid).toBeNull()

    const valid = resolveInterruptedRunSnapshot(
      {
        stage: 2,
        atStatus: 'paused',
        savedAt: '2026-03-24T18:10:00.000Z'
      },
      1
    )

    expect(valid).not.toBeNull()
    expect(valid?.stage).toBe(2)
    expect(valid?.atStatus).toBe('paused')
  })

  it('renderiza mapa da campanha com estados locked, unlocked e completed', () => {
    const onSelectStage = vi.fn()

    render(
      <CampaignMap
        highestUnlockedStage={3}
        currentStage={2}
        completedStages={[1, 2]}
        onSelectStage={onSelectStage}
      />
    )

    expect(screen.getByText('Fase 1')).toBeInTheDocument()
    expect(screen.getByText('Fase 5')).toBeInTheDocument()
    expect(screen.getAllByText('Derrote o chefe da fase anterior para desbloquear').length).toBeGreaterThan(0)

    const stageThreeButton = screen.getByRole('button', { name: /Fase 3/i })
    fireEvent.click(stageThreeButton)
    expect(onSelectStage).toHaveBeenCalledWith(3)
  })

  it('mostra copy de fase completada e prompt de run interrompida com acoes', () => {
    const onPrimary = vi.fn()
    const onContinueStage = vi.fn()
    const onResume = vi.fn()
    const onRestart = vi.fn()

    const { rerender } = render(
      <GameOverlay
        status="running"
        showCompletion={true}
        onPrimaryAction={onPrimary}
        onContinueStage={onContinueStage}
      />
    )

    expect(screen.getByRole('heading', { name: 'FASE COMPLETADA' })).toBeInTheDocument()
    expect(screen.getByRole('button', { name: 'Proxima fase' })).toBeInTheDocument()

    rerender(
      <GameOverlay
        status="idle"
        showInterruptedRunPrompt={true}
        onPrimaryAction={onPrimary}
        onResumeInterruptedRun={onResume}
        onRestartInterruptedRun={onRestart}
      />
    )

    expect(screen.getByRole('heading', { name: 'Run interrompida encontrada' })).toBeInTheDocument()
    fireEvent.click(screen.getByRole('button', { name: 'Continuar' }))
    fireEvent.click(screen.getByRole('button', { name: 'Reiniciar' }))
    expect(onResume).toHaveBeenCalledTimes(1)
    expect(onRestart).toHaveBeenCalledTimes(1)
  })

  it('replay de fase concluida nao reduz progressao desbloqueada', async () => {
    await savePersistedProgressProfile({
      highestUnlockedStage: 4,
      totalRuns: 10,
      lastAttemptedStage: 2,
      lastCompletedStage: 3,
      interruptedRun: null
    })

    await savePersistedProgressProfile({
      highestUnlockedStage: 4,
      totalRuns: 11,
      lastAttemptedStage: 1,
      lastCompletedStage: 3,
      interruptedRun: null
    })

    const latest = putRecordMock.mock.calls[putRecordMock.mock.calls.length - 1]?.[1]
    expect(latest.highestUnlockedStage).toBe(4)
    expect(latest.lastCompletedStage).toBe(3)
  })
})

import { saveLocalHighscore } from '../services/highscoreService'
import { logTelemetryEvent } from '../lib/telemetry'
import {
  getPersistedProgressProfile,
  savePersistedProgressProfile
} from '../services/shopPersistenceService'
import type { UpgradeLevels } from '../services/shopService'
import { getCycleIndex, isBossStage } from './config/gameplay'
import { createEnemyGrid } from './entities/enemy'
import { clampActiveDropsByStage } from './config/performance'
import type { RareDropEntity } from './entities/dropItem'
import { createPlayer, movePlayer, tickPlayer, tryConsumeShot, type PlayerEntity } from './entities/player'
import {
  createHomingMissileProjectile,
  createLaserProjectile,
  createPlayerProjectile,
  steerHomingProjectiles,
  stepProjectiles,
  type ProjectileEntity
} from './entities/projectile'
import { createInputManager } from './input/inputManager'
import { createGameLoop, type GameLoopController } from './loop'
import { gameStore } from '../state/gameStore'
import {
  checkEnemyReachedPlayerLine,
  resolveBossProjectileCollisions,
  resolvePlayerDropCollisions,
  resolveEnemyProjectileHitsPlayer,
  resolvePlayerProjectileCollisions
} from './systems/collisionSystem'
import { emitBossProjectiles } from './systems/bossAttackSystem'
import { spawnBossForWave, tickBoss } from './systems/bossSystem'
import { removeExpiredDrops, resolveCollectedSpecialShot, stepDrops } from './systems/dropSystem'
import { createShopRunModifierOffer, evaluateStageProgression } from './systems/progressionSystem'
import { addOrRefreshPowerUp, getActiveWeaponPowerUp, removeExpiredPowerUps } from './systems/powerUpSystem'
import { updateScoreAndLives } from './systems/scoreLivesSystem'
import { applyPlayerUpgrades } from './systems/upgradeSystem'
import {
  applyWaveEnemies,
  createDropsFromDefeatedEnemies,
  emitEnemyProjectiles,
  stepEnemies,
  type WaveState
} from './systems/waveSystem'

let context: CanvasRenderingContext2D | null = null
let loopController: GameLoopController | null = null
const inputManager = createInputManager()
let player: PlayerEntity | null = null
let wave: WaveState = {
  stage: 1,
  enemies: createEnemyGrid(1),
  boss: null,
  direction: 1
}
let projectiles: ProjectileEntity[] = []
let activeDrops: RareDropEntity[] = []
let pendingStage: number | null = null
let currentRunId = 'run-0'
let currentRunSeed = 'seed-0'
let bossEncounterStartLives: number | null = null

type BossEncounterSnapshot = ReturnType<typeof gameStore.getState>['bossEncounter']

function getBossEncounterAttemptForStage(stage: number): number {
  const encounter = gameStore.getState().bossEncounter
  if (encounter.stage === stage) {
    return encounter.attempt + 1
  }

  return 1
}

function updateBossEncounterFromWave(partial?: Partial<BossEncounterSnapshot>): void {
  const state = gameStore.getState()
  const existing = state.bossEncounter
  const nextHealth = wave.boss?.health ?? 0
  const nextMaxHealth = wave.boss?.maxHealth ?? 0
  const livesBase = bossEncounterStartLives ?? state.lives

  gameStore.setState({
    bossEncounter: {
      ...existing,
      active: Boolean(wave.boss),
      bossId: wave.boss?.id ?? null,
      stage: wave.boss?.stage ?? existing.stage,
      health: nextHealth,
      maxHealth: nextMaxHealth,
      damageTaken: wave.boss ? Math.max(existing.damageTaken, livesBase - state.lives) : existing.damageTaken,
      ...partial
    }
  })
}

function startBossEncounter(nowMs: number): void {
  const state = gameStore.getState()
  bossEncounterStartLives = state.lives
  updateBossEncounterFromWave({
    stage: wave.stage,
    attempt: getBossEncounterAttemptForStage(wave.stage),
    startedAtMs: nowMs,
    endedAtMs: null,
    outcome: 'in-progress',
    damageTaken: 0
  })
}

function handleBossVictory(nowMs: number): void {
  const state = gameStore.getState()
  const livesBase = bossEncounterStartLives ?? state.lives

  gameStore.setState({
    bossEncounter: {
      ...state.bossEncounter,
      active: false,
      endedAtMs: nowMs,
      outcome: 'victory',
      bossId: state.bossEncounter.bossId,
      health: 0,
      maxHealth: state.bossEncounter.maxHealth,
      damageTaken: Math.max(state.bossEncounter.damageTaken, livesBase - state.lives)
    }
  })
  bossEncounterStartLives = null
}

function handleBossPlayerDefeat(nowMs: number): void {
  const state = gameStore.getState()
  const livesBase = bossEncounterStartLives ?? state.lives

  gameStore.setState({
    bossEncounter: {
      ...state.bossEncounter,
      active: false,
      endedAtMs: nowMs,
      outcome: 'defeat',
      damageTaken: Math.max(state.bossEncounter.damageTaken, livesBase - state.lives)
    }
  })
  bossEncounterStartLives = null
}

function syncStore(): void {
  const state = gameStore.getState()
  gameStore.setState({
    score: state.score,
    lives: state.lives,
    stage: wave.stage,
    bossEncounter: {
      ...state.bossEncounter,
      active: Boolean(wave.boss),
      bossId: wave.boss?.id ?? null,
      stage: wave.boss?.stage ?? state.bossEncounter.stage,
      health: wave.boss?.health ?? 0,
      maxHealth: wave.boss?.maxHealth ?? 0
    },
    activeDrops: activeDrops.map((drop) => ({
      id: drop.id,
      x: drop.x,
      y: drop.y,
      width: drop.width,
      height: drop.height,
      grantedShotType: drop.grantedShotType,
      expiresAtMs: drop.expiresAtMs
    })),
    input: inputManager.readInput()
  })
}

function resetRoundState(canvas: HTMLCanvasElement, stage = 1): void {
  player = createPlayer(canvas.width, canvas.height)
  wave = {
    stage,
    enemies: createEnemyGrid(stage),
    boss: null,
    direction: 1
  }
  projectiles = []
  activeDrops = []
  pendingStage = null
  currentRunId = 'run-0'
  currentRunSeed = 'seed-0'
  bossEncounterStartLives = null
}

function update(deltaSeconds: number): void {
  if (!context || !player) {
    return
  }

  const state = gameStore.getState()
  if (state.status !== 'running') {
    return
  }

  const input = inputManager.readInput()
  const nowMs = Date.now()
  if (input.pause) {
    pauseGame()
    return
  }

  let activePowerUps = removeExpiredPowerUps(state.activePowerUps, nowMs)
  activeDrops = removeExpiredDrops(activeDrops, nowMs)
  activeDrops = stepDrops(activeDrops, deltaSeconds, context.canvas.height)

  player = tickPlayer(player, deltaSeconds)
  player = movePlayer(player, input.horizontal, deltaSeconds, context.canvas.width)

  if (input.fire) {
    const [nextPlayer, shouldShoot] = tryConsumeShot(player)
    player = nextPlayer

    if (shouldShoot) {
      const weaponPowerUp = getActiveWeaponPowerUp(activePowerUps)
      if (weaponPowerUp === 'laser') {
        projectiles.push(createLaserProjectile(player.x + player.width / 2 - 4, player.y - 12))
      } else if (weaponPowerUp === 'homing-missile') {
        projectiles.push(createHomingMissileProjectile(player.x + player.width / 2 - 3, player.y - 12))
      } else {
        projectiles.push(createPlayerProjectile(player.x + player.width / 2 - 2, player.y - 10))
      }
    }
  }

  const targetX = wave.boss ? wave.boss.x + wave.boss.width / 2 : wave.enemies[0]?.x ?? null
  projectiles = steerHomingProjectiles(projectiles, targetX, deltaSeconds)
  wave = stepEnemies(wave, deltaSeconds, context.canvas.width)
  wave = tickBoss(wave, deltaSeconds, context.canvas.width)
  projectiles = stepProjectiles(projectiles, deltaSeconds, context.canvas.height)

  const enemyShotsUpdate = emitEnemyProjectiles(wave, projectiles, player.x + player.width / 2)
  wave = enemyShotsUpdate.wave
  projectiles = enemyShotsUpdate.projectiles

  const bossShotResult = emitBossProjectiles(wave, projectiles, player.x + player.width / 2)
  wave = bossShotResult.wave
  projectiles = bossShotResult.projectiles

  const collisionResult = resolvePlayerProjectileCollisions(wave.enemies, projectiles)
  if (collisionResult.defeatedEnemies.length > 0) {
    const spawnedDrops = createDropsFromDefeatedEnemies(collisionResult.defeatedEnemies, nowMs)

    if (spawnedDrops.length > 0) {
      const merged = [...activeDrops, ...spawnedDrops]
      const allowedCount = clampActiveDropsByStage(wave.stage, merged.length)
      activeDrops = merged.slice(-allowedCount)
    }
  }
  wave = applyWaveEnemies(wave, collisionResult.enemies)
  projectiles = collisionResult.projectiles

  const bossBeforeCollision = wave.boss
  const bossCollisionResult = resolveBossProjectileCollisions(wave.boss, projectiles)
  wave = {
    ...wave,
    boss: bossCollisionResult.boss
  }
  projectiles = bossCollisionResult.projectiles

  const playerHitResult = resolveEnemyProjectileHitsPlayer(player, projectiles, deltaSeconds, false)
  projectiles = playerHitResult.projectiles

  const dropCollision = resolvePlayerDropCollisions(player, activeDrops)
  activeDrops = dropCollision.drops
  if (dropCollision.collectedShots.length > 0) {
    for (const shotType of dropCollision.collectedShots) {
      const currentWeapon = getActiveWeaponPowerUp(activePowerUps)
      const resolvedShot = resolveCollectedSpecialShot(shotType, currentWeapon)
      activePowerUps = addOrRefreshPowerUp(activePowerUps, resolvedShot, nowMs)
    }
  }

  const progression = evaluateStageProgression(
    wave.stage,
    wave.enemies.length,
    Boolean(wave.boss),
    bossCollisionResult.bossDefeated
  )

  if (progression.enterBossFight) {
    wave = spawnBossForWave(wave, getBossEncounterAttemptForStage(wave.stage))
    startBossEncounter(nowMs)
    return
  }

  if (progression.enterShop) {
    if (bossCollisionResult.bossDefeated) {
      handleBossVictory(nowMs)
    }

    pendingStage = progression.nextStage

    const bossPoints = bossCollisionResult.bossDefeated ? (bossBeforeCollision?.points ?? 0) : 0
    const nextScore = state.score + bossPoints
    const highScoreWithBoss = Math.max(state.highScore, nextScore)

    void getPersistedProgressProfile().then((profile) => {
      void savePersistedProgressProfile({
        highestUnlockedStage: Math.max(profile.highestUnlockedStage, progression.nextStage),
        totalRuns: profile.totalRuns,
        lastAttemptedStage: profile.lastAttemptedStage,
        lastCompletedStage: Math.max(wave.stage, profile.lastCompletedStage ?? 0),
        interruptedRun: null
      })
    })

    const runModifierOffer = createShopRunModifierOffer({
      runId: currentRunId,
      stageNumber: wave.stage,
      runSeed: currentRunSeed,
      upgradeLevels: state.upgradeLevels
    })

    gameStore.setState({
      status: 'shop',
      score: nextScore,
      lives: state.lives,
      stage: wave.stage,
      highScore: highScoreWithBoss,
      progressionProfile: {
        highestUnlockedStage: Math.max(state.progressionProfile.highestUnlockedStage, progression.nextStage),
        totalRuns: state.progressionProfile.totalRuns,
        lastAttemptedStage: state.progressionProfile.lastAttemptedStage,
        lastCompletedStage: Math.max(wave.stage, state.progressionProfile.lastCompletedStage ?? 0),
        interruptedRun: null
      },
      bossEncounter: {
        ...gameStore.getState().bossEncounter,
        active: false,
        bossId: null,
        health: 0
      },
      runModifierOffer,
      activePowerUps,
      activeDrops,
      input
    })
    pauseGameLoop()
    return
  }

  const enemyReachedBottom = checkEnemyReachedPlayerLine(wave.enemies, player)
  const scoreLives = updateScoreAndLives({
    score: state.score,
    lives: state.lives,
    defeatedEnemyCount: collisionResult.defeatedEnemyCount,
    enemyReachedBottom,
    playerHitCount: playerHitResult.playerHitCount,
    bonusScore: bossCollisionResult.bossDefeated ? (bossBeforeCollision?.points ?? 0) : 0
  })

  const highScore = Math.max(state.highScore, scoreLives.score)

  if (scoreLives.isGameOver) {
    if (wave.boss || state.bossEncounter.active) {
      handleBossPlayerDefeat(nowMs)
    }

    gameStore.setState({
      status: 'game-over',
      score: scoreLives.score,
      lives: scoreLives.lives,
      highScore,
      stage: wave.stage,
      bossEncounter: {
        ...gameStore.getState().bossEncounter,
        active: false,
        bossId: wave.boss?.id ?? gameStore.getState().bossEncounter.bossId,
        stage: wave.boss?.stage ?? gameStore.getState().bossEncounter.stage,
        health: wave.boss?.health ?? 0,
        maxHealth: wave.boss?.maxHealth ?? gameStore.getState().bossEncounter.maxHealth,
        damageTaken: Math.max(gameStore.getState().bossEncounter.damageTaken, (bossEncounterStartLives ?? state.lives) - scoreLives.lives)
      },
      activePowerUps,
      activeDrops,
      input
    })

    void saveLocalHighscore(scoreLives.score)
    pauseGameLoop()
    return
  }

  if (enemyReachedBottom) {
    player = createPlayer(context.canvas.width, context.canvas.height)
    wave = {
      ...wave,
      enemies: createEnemyGrid(wave.stage)
    }
    projectiles = []
  }

  gameStore.setState({
    score: scoreLives.score,
    lives: scoreLives.lives,
    highScore,
    stage: wave.stage,
    bossEncounter: {
      ...state.bossEncounter,
      active: Boolean(wave.boss),
      bossId: wave.boss?.id ?? state.bossEncounter.bossId,
      stage: wave.boss?.stage ?? state.bossEncounter.stage,
      health: wave.boss?.health ?? 0,
      maxHealth: wave.boss?.maxHealth ?? state.bossEncounter.maxHealth,
      damageTaken: wave.boss
        ? Math.max(state.bossEncounter.damageTaken, (bossEncounterStartLives ?? state.lives) - scoreLives.lives)
        : state.bossEncounter.damageTaken
    },
    activePowerUps,
    activeDrops,
    input
  })
}

function render(): void {
  if (!context || !player) {
    return
  }

  const { canvas } = context
  context.clearRect(0, 0, canvas.width, canvas.height)
  context.fillStyle = '#020617'
  context.fillRect(0, 0, canvas.width, canvas.height)

  context.fillStyle = '#38bdf8'
  context.fillRect(player.x, player.y, player.width, player.height)

  context.fillStyle = '#a3e635'
  for (const enemy of wave.enemies) {
    context.fillRect(enemy.x, enemy.y, enemy.width, enemy.height)
  }

  if (wave.boss) {
    context.fillStyle = '#f97316'
    context.fillRect(wave.boss.x, wave.boss.y, wave.boss.width, wave.boss.height)
  }

  context.fillStyle = '#f8fafc'
  for (const projectile of projectiles) {
    context.fillRect(projectile.x, projectile.y, projectile.width, projectile.height)
  }

  context.fillStyle = '#fbbf24'
  for (const drop of activeDrops) {
    context.fillRect(drop.x, drop.y, drop.width, drop.height)
  }
}

function pauseGameLoop(): void {
  if (!loopController) {
    return
  }

  loopController.pause()
}

function createInterruptedRunPayload(stage: number): { stage: number; atStatus: 'running' | 'paused'; savedAt: string } {
  return {
    stage,
    atStatus: 'paused',
    savedAt: new Date().toISOString()
  }
}

export function startGame(canvas: HTMLCanvasElement): void {
  context = canvas.getContext('2d')
  if (!context) {
    return
  }

  resetRoundState(canvas, gameStore.getState().stage)
  inputManager.connect(canvas)

  loopController = createGameLoop({
    update,
    render
  })

  loopController.start()
  syncStore()
}

export function stopGame(): void {
  loopController?.stop()
  loopController = null
  inputManager.disconnect()
}

export function startRound(): void {
  if (!context) {
    return
  }

  if (!player) {
    player = createPlayer(context.canvas.width, context.canvas.height)
  }

  const state = gameStore.getState()
  resetRoundState(context.canvas, state.stage)

  const nextRunOrdinal = Math.max(1, state.progressionProfile.totalRuns + 1)
  currentRunId = `run-${nextRunOrdinal}`
  currentRunSeed = `${nextRunOrdinal}-${Date.now()}-${state.highScore}`

  if (player) {
    player = applyPlayerUpgrades(player, state.upgradeLevels)
  }

  gameStore.setState({
    status: 'running',
    bossEncounter: {
      ...state.bossEncounter,
      active: false,
      bossId: null,
      health: 0,
      maxHealth: 0,
      outcome: 'none',
      startedAtMs: null,
      endedAtMs: null,
      damageTaken: 0
    }
  })

  void getPersistedProgressProfile().then((profile) => {
    const nextRuns = profile.totalRuns + 1
    const stageCheckpoint = gameStore.getState().stage
    gameStore.setState({
      progressionProfile: {
        highestUnlockedStage: profile.highestUnlockedStage,
        totalRuns: nextRuns,
        lastAttemptedStage: stageCheckpoint,
        lastCompletedStage: profile.lastCompletedStage,
        interruptedRun: null
      }
    })

    void savePersistedProgressProfile({
      highestUnlockedStage: profile.highestUnlockedStage,
      totalRuns: nextRuns,
      lastAttemptedStage: stageCheckpoint,
      lastCompletedStage: profile.lastCompletedStage,
      interruptedRun: null
    })
  })

  loopController?.resume()
}

export function pauseGame(): void {
  const state = gameStore.getState()
  if (state.status !== 'running') {
    return
  }

  const interruptedRun = createInterruptedRunPayload(state.stage)

  gameStore.setState({
    status: 'paused',
    progressionProfile: {
      ...state.progressionProfile,
      interruptedRun
    }
  })

  void getPersistedProgressProfile().then((profile) => {
    void savePersistedProgressProfile({
      highestUnlockedStage: profile.highestUnlockedStage,
      totalRuns: profile.totalRuns,
      lastAttemptedStage: profile.lastAttemptedStage,
      lastCompletedStage: profile.lastCompletedStage,
      interruptedRun
    })
  })

  pauseGameLoop()
}

export function resumeGame(): void {
  if (gameStore.getState().status !== 'paused') {
    return
  }

  gameStore.setState({
    status: 'running'
  })
  loopController?.resume()
}

export function restartRound(): void {
  if (!context) {
    return
  }

  const stageToRetry = gameStore.getState().stage
  gameStore.reset()
  gameStore.setState({ stage: stageToRetry })
  resetRoundState(context.canvas, stageToRetry)
  gameStore.setState({
    status: 'running'
  })
  loopController?.resume()
}

export function continueToNextStage(upgradeLevels: UpgradeLevels): void {
  if (!context || pendingStage === null) {
    return
  }

  wave = {
    stage: pendingStage,
    enemies: createEnemyGrid(pendingStage),
    boss: null,
    direction: 1
  }
  pendingStage = null
  projectiles = []
  activeDrops = []
  bossEncounterStartLives = null

  if (player) {
    player = applyPlayerUpgrades(player, upgradeLevels)
  }

  void logTelemetryEvent('cycle-stage-advanced', {
    stage: wave.stage,
    cycle: getCycleIndex(wave.stage),
    bossStage: isBossStage(wave.stage)
  })

  gameStore.setState({
    status: 'running',
    stage: wave.stage,
    upgradeLevels,
    runModifierOffer: null,
    activeDrops,
    bossEncounter: {
      ...gameStore.getState().bossEncounter,
      active: false,
      bossId: null,
      health: 0,
      maxHealth: 0,
      outcome: 'none',
      startedAtMs: null,
      endedAtMs: null,
      damageTaken: 0
    }
  })

  loopController?.resume()
}

import type { ActivePowerUpState, GameStatus } from '../game/types'

type GameOverlayProps = {
  status: GameStatus
  activePowerUps?: ActivePowerUpState[]
  bossHealth?: number
  bossMaxHealth?: number
  nowMs?: number
  showCompletion?: boolean
  showInterruptedRunPrompt?: boolean
  onPrimaryAction: () => void
  onContinueStage?: () => void
  onResumeInterruptedRun?: () => void
  onRestartInterruptedRun?: () => void
}

function getOverlayCopy(status: GameStatus): { title: string; buttonLabel: string } | null {
  if (status === 'idle') {
    return {
      title: 'Pronto para jogar?',
      buttonLabel: 'Iniciar rodada'
    }
  }

  if (status === 'paused') {
    return {
      title: 'Jogo pausado',
      buttonLabel: 'Continuar'
    }
  }

  if (status === 'game-over') {
    return {
      title: 'Game Over',
      buttonLabel: 'Reiniciar'
    }
  }

  return null
}

export function GameOverlay({
  status,
  activePowerUps = [],
  bossHealth,
  bossMaxHealth,
  nowMs = Date.now(),
  showCompletion = false,
  showInterruptedRunPrompt = false,
  onPrimaryAction,
  onContinueStage,
  onResumeInterruptedRun,
  onRestartInterruptedRun
}: GameOverlayProps) {
  const copy = getOverlayCopy(status)
  const hasActivePowerUps = activePowerUps.length > 0

  return (
    <>
      <div className="pointer-events-none absolute bottom-3 left-3 z-20 rounded-md bg-slate-900/80 px-3 py-2 text-xs text-slate-100 backdrop-blur">
        <p className="font-medium">Power-ups ativos</p>
        {hasActivePowerUps ? (
          <ul>
            {activePowerUps.map((powerUp) => {
              const remainingSeconds = Math.max(0, Math.ceil((powerUp.expiresAtMs - nowMs) / 1000))
              return (
                <li key={powerUp.type} className="text-slate-300">
                  {powerUp.type}: {remainingSeconds}s
                </li>
              )
            })}
          </ul>
        ) : (
          <p className="text-slate-400">Nenhum</p>
        )}
      </div>

      {typeof bossHealth === 'number' && typeof bossMaxHealth === 'number' && bossMaxHealth > 0 ? (
        <div className="pointer-events-none absolute bottom-3 right-3 z-20 rounded-md bg-slate-900/80 px-3 py-2 text-xs text-orange-200 backdrop-blur">
          <p className="font-medium">Boss HP: {bossHealth}/{bossMaxHealth}</p>
        </div>
      ) : null}

      {showInterruptedRunPrompt ? (
        <div className="absolute inset-0 z-30 grid place-items-center bg-black/65">
          <div className="w-full max-w-lg rounded-xl border border-slate-700 bg-slate-900/95 p-6 text-center shadow-xl">
            <h2 className="mb-4 text-[28px] font-semibold leading-tight text-white">Run interrompida encontrada</h2>
            <p className="mb-6 text-base font-normal text-slate-200">Reiniciar fase: Reiniciar agora? O progresso da run atual sera perdido.</p>
            <div className="flex items-center justify-center gap-4">
              <button
                className="rounded-md bg-indigo-600 px-4 py-2 text-sm font-semibold text-white transition hover:bg-indigo-500"
                onClick={onResumeInterruptedRun}
                type="button"
              >
                Continuar
              </button>
              <button
                className="rounded-md bg-red-600 px-4 py-2 text-sm font-semibold text-white transition hover:bg-red-500"
                onClick={onRestartInterruptedRun}
                type="button"
              >
                Reiniciar
              </button>
            </div>
          </div>
        </div>
      ) : null}

      {showCompletion ? (
        <div className="absolute inset-0 z-30 grid place-items-center bg-black/65">
          <div className="w-full max-w-lg rounded-xl border border-slate-700 bg-slate-900/95 p-6 text-center shadow-xl">
            <h2 className="mb-3 text-[28px] font-semibold leading-tight text-white">FASE COMPLETADA</h2>
            <p className="mb-6 text-base font-normal text-slate-200">Recompensa aplicada. Voce desbloqueou a proxima fase da campanha.</p>
            <button
              className="rounded-md bg-indigo-600 px-4 py-2 text-sm font-semibold text-white transition hover:bg-indigo-500"
              onClick={onContinueStage}
              type="button"
            >
              Proxima fase
            </button>
          </div>
        </div>
      ) : null}

      {copy ? (
        <div className="absolute inset-0 z-30 grid place-items-center bg-black/65">
          <div className="rounded-xl border border-slate-700 bg-slate-900/95 p-6 text-center shadow-xl">
            <h2 className="mb-4 text-2xl font-semibold text-white">{copy.title}</h2>
            <button
              className="rounded-md bg-indigo-600 px-4 py-2 text-sm font-medium text-white transition hover:bg-indigo-500"
              onClick={onPrimaryAction}
              type="button"
            >
              {copy.buttonLabel}
            </button>
          </div>
        </div>
      ) : null}
    </>
  )
}

import { EMPTY_INPUT, type GameSessionState } from '../game/types'
import { EMPTY_UPGRADE_LEVELS } from '../services/shopService'

type GameStoreListener = (state: GameSessionState) => void

const initialState: GameSessionState = {
  status: 'idle',
  score: 0,
  lives: 3,
  stage: 1,
  highScore: 0,
  activeUpgrades: [],
  upgradeLevels: { ...EMPTY_UPGRADE_LEVELS },
  activePowerUps: [],
  activeDrops: [],
  bossEncounter: {
    active: false,
    bossId: null,
    stage: null,
    attempt: 0,
    startedAtMs: null,
    endedAtMs: null,
    outcome: 'none',
    damageTaken: 0,
    health: 0,
    maxHealth: 0
  },
  progressionProfile: {
    highestUnlockedStage: 1,
    totalRuns: 0,
    lastAttemptedStage: null,
    lastCompletedStage: null,
    interruptedRun: null
  },
  runModifierOffer: null,
  input: EMPTY_INPUT
}

class GameStore {
  private state: GameSessionState = initialState
  private listeners = new Set<GameStoreListener>()

  getState(): GameSessionState {
    return this.state
  }

  setState(partial: Partial<GameSessionState>): void {
    this.state = {
      ...this.state,
      ...partial
    }

    this.listeners.forEach((listener) => listener(this.state))
  }

  reset(): void {
    this.state = {
      ...initialState,
      highScore: this.state.highScore,
      progressionProfile: this.state.progressionProfile,
      activeDrops: []
    }
    this.listeners.forEach((listener) => listener(this.state))
  }

  subscribe(listener: GameStoreListener): () => void {
    this.listeners.add(listener)
    listener(this.state)

    return () => {
      this.listeners.delete(listener)
    }
  }
}

export const gameStore = new GameStore()

